let currentPage = 1;
const itemsPerPage = 4;
let searchQuery = "";
let selectedCategory = "all";
let sortOrder = "newest";
document.addEventListener("DOMContentLoaded", () => {
setupMobileMenu();
setupTheme();
setupLanguage();
setupNewsControls();
renderNews();
});
function setupMobileMenu() {
const hamburger = document.getElementById("hamburger");
const navMenu = document.getElementById("navMenu");
const navLinks = document.querySelectorAll(".nav-link");
if (hamburger && navMenu) {
hamburger.addEventListener("click", () => {
hamburger.classList.toggle("open");
navMenu.classList.toggle("open");
});
navLinks.forEach(link => {
link.addEventListener("click", () => {
hamburger.classList.remove("open");
navMenu.classList.remove("open");
});
});
}
}
function setupTheme() {
const themeToggleBtn = document.getElementById("themeToggle");
const currentTheme = localStorage.getItem("theme");
if (currentTheme === "light") {
document.body.classList.add("light-mode");
}
if (themeToggleBtn) {
themeToggleBtn.addEventListener("click", () => {
document.body.classList.toggle("light-mode");
const theme = document.body.classList.contains("light-mode") ? "light" : "dark";
localStorage.setItem("theme", theme);
});
}
}
function setupLanguage() {
const langSelect = document.getElementById("langSelect");
let currentLang = localStorage.getItem("language") || "tr";
if (langSelect) {
langSelect.value = currentLang;
langSelect.addEventListener("change", (e) => {
const selectedLang = e.target.value;
localStorage.setItem("language", selectedLang);
updatePageLanguage(selectedLang);
document.documentElement.lang = selectedLang;
renderNews();
});
}
updatePageLanguage(currentLang);
}
function updatePageLanguage(lang) {
const translatableElements = document.querySelectorAll("[data-i18n]");
translatableElements.forEach(element => {
const key = element.getAttribute("data-i18n");
if (translations[key] && translations[key][lang]) {
element.textContent = translations[key][lang];
}
});
const searchInput = document.getElementById("newsSearchInput");
if (searchInput) {
searchInput.placeholder = lang === "tr" ? "Haberlerde arayın..." : "Search news...";
}
}
function setupNewsControls() {
const searchInput = document.getElementById("newsSearchInput");
const categorySelect = document.getElementById("newsCategorySelect");
const sortSelect = document.getElementById("newsSortSelect");
if (searchInput) {
searchInput.addEventListener("input", (e) => {
searchQuery = e.target.value.toLowerCase().trim();
currentPage = 1;
renderNews();
});
}
if (categorySelect) {
categorySelect.addEventListener("change", (e) => {
selectedCategory = e.target.value;
currentPage = 1;
renderNews();
});
}
if (sortSelect) {
sortSelect.addEventListener("change", (e) => {
sortOrder = e.target.value;
currentPage = 1;
renderNews();
});
}
}
function renderNews() {
const gridContainer = document.getElementById("newsGrid");
const paginationContainer = document.getElementById("newsPagination");
if (!gridContainer || !paginationContainer) return;
const lang = localStorage.getItem("language") || "tr";
let filtered = newsData.filter(item => {
if (selectedCategory !== "all" && item.category !== selectedCategory) {
return false;
}
if (searchQuery !== "") {
const title = lang === "tr" ? item.titleTR.toLowerCase() : item.titleEN.toLowerCase();
const summary = lang === "tr" ? item.summaryTR.toLowerCase() : item.summaryEN.toLowerCase();
if (!title.includes(searchQuery) && !summary.includes(searchQuery)) {
return false;
}
}
return true;
});
filtered.sort((a, b) => {
const timeA = new Date(a.dateValue).getTime();
const timeB = new Date(b.dateValue).getTime();
return sortOrder === "newest" ? timeB - timeA : timeA - timeB;
});
const totalItems = filtered.length;
const totalPages = Math.ceil(totalItems / itemsPerPage) || 1;
if (currentPage > totalPages) {
currentPage = totalPages;
}
const startIndex = (currentPage - 1) * itemsPerPage;
const endIndex = startIndex + itemsPerPage;
const paginatedItems = filtered.slice(startIndex, endIndex);
if (paginatedItems.length === 0) {
const noResultsText = translations["no_results"][lang];
gridContainer.innerHTML = `<div class="news-no-results">${noResultsText}</div>`;
} else {
let gridHtml = "";
paginatedItems.forEach(item => {
const dateText = lang === "tr" ? item.dateTextTR : item.dateTextEN;
const catText = lang === "tr" ? item.categoryTR : item.categoryEN;
const title = lang === "tr" ? item.titleTR : item.titleEN;
const summary = lang === "tr" ? item.summaryTR : item.summaryEN;
const readMoreText = translations["read_more"][lang];
gridHtml += `
<article class="news-card">
<div class="news-card-img-wrapper">
<img src="${item.imgUrl}" alt="${title}" class="news-card-img" />
<span class="news-category-badge badge-${item.category}">${catText}</span>
</div>
<div class="news-card-body">
<div class="news-card-date">${dateText}</div>
<h2 class="news-card-title">${title}</h2>
<p class="news-card-desc">${summary}</p>
<a href="news-detail.html?id=${item.id}" class="news-card-btn">
<span>${readMoreText}</span>
<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
<path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
</svg>
</a>
</div>
</article>
`;
});
gridContainer.innerHTML = gridHtml;
}
const prevText = translations["pagination_prev"][lang];
const nextText = translations["pagination_next"][lang];
const pageInfoText = lang === "tr" ? `Sayfa ${currentPage} / ${totalPages}` : `Page ${currentPage} / ${totalPages}`;
let paginationHtml = `
<button class="pagination-btn prev-btn" id="newsPrevBtn" ${currentPage === 1 ? "disabled" : ""}>
<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
<path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
</svg>
<span>${prevText}</span>
</button>
<div class="pagination-info">
<span>${pageInfoText}</span>
</div>
<button class="pagination-btn next-btn" id="newsNextBtn" ${currentPage === totalPages ? "disabled" : ""}>
<span>${nextText}</span>
<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
<path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
</svg>
</button>
`;
paginationContainer.innerHTML = paginationHtml;
document.getElementById("newsPrevBtn").addEventListener("click", () => {
if (currentPage > 1) {
currentPage--;
renderNews();
document.querySelector(".news-hero").scrollIntoView({ behavior: "smooth" });
}
});
document.getElementById("newsNextBtn").addEventListener("click", () => {
if (currentPage < totalPages) {
currentPage++;
renderNews();
document.querySelector(".news-hero").scrollIntoView({ behavior: "smooth" });
}
});
}